// Validate and normalize incoming request
const body = $input.first().json.body || {};

const grade = (body.grade || '').toString().trim() || 'غير محدد';
const subject = (body.subject || '').toString().trim() || 'غير محدد';
const lessonTitle = (body.lessonTitle || '').toString().trim() || 'الدرس الحالي';
const availableStrategies = Array.isArray(body.availableStrategies) ? body.availableStrategies.filter(Boolean) : [];
const availableTools = Array.isArray(body.availableTools) ? body.availableTools.filter(Boolean) : [];
const availableGoals = Array.isArray(body.availableGoals) ? body.availableGoals.filter(Boolean) : [];
const availableActivities = Array.isArray(body.availableActivities) ? body.availableActivities.filter(Boolean) : [];
const lessonPath = (body.lessonPath || '').toString().trim();
const unitName = (body.unitName || '').toString().trim();

return [{
  json: {
    grade,
    subject,
    lessonTitle,
    lessonPath,
    unitName,
    availableStrategies,
    availableTools,
    availableGoals,
    availableActivities,
    strategiesText: availableStrategies.length ? availableStrategies.map((s, i) => `${i + 1}. ${s}`).join('\n') : 'لا توجد خيارات متاحة',
    toolsText: availableTools.length ? availableTools.map((s, i) => `${i + 1}. ${s}`).join('\n') : 'لا توجد خيارات متاحة',
    goalsText: availableGoals.length ? availableGoals.map((s, i) => `${i + 1}. ${s}`).join('\n') : 'لا توجد أهداف متاحة',
    activitiesText: availableActivities.length ? availableActivities.map((s, i) => `${i + 1}. ${s}`).join('\n') : 'لا توجد أنشطة متاحة'
  }
}];

