// Parse and validate AI response
const response = $input.first().json;
const inputData = $('Validate Input').first().json;

let aiContent;
try {
  const rawContent = response.choices && response.choices[0] && response.choices[0].message && response.choices[0].message.content;
  if (!rawContent) {
    throw new Error('No content from AI');
  }
  aiContent = typeof rawContent === 'string' ? JSON.parse(rawContent) : rawContent;
} catch (err) {
  // Fallback: return safe defaults so the extension does not crash
  return [{
    json: {
      LectureClassPreparationText: `تمهيد لدرس ${inputData.lessonTitle} بربطه بالمعارف السابقة في ${inputData.subject}`,
      LessonVocabulary: `المفردات الأساسية لدرس ${inputData.lessonTitle}`,
      ThinkingSkills: 'الملاحظة، التحليل، الاستنتاج، حل المشكلات',
      LectureClassCloseText: `تلخيص أهم ما تعلمه الطلاب في درس ${inputData.lessonTitle}`,
      TeacherNote: `يراعى تنوع مستويات الطلاب أثناء شرح درس ${inputData.lessonTitle}`,
      goals: [],
      strategies: [],
      tools: [],
      activities: [],
      homework: `حل تمارين درس ${inputData.lessonTitle} في كتاب الطالب`,
      preparationActivity: `نشاط افتتاحي لدرس ${inputData.lessonTitle}`,
      closureActivity: `نشاط ختامي لدرس ${inputData.lessonTitle}`,
      examGoal: `قياس مدى استيعاب الطلاب لدرس ${inputData.lessonTitle}`,
      _fallback: true,
      _error: err.message
    }
  }];
}

// Strip markdown chars defensively (** __ ## etc.)
function stripMarkdown(str) {
  if (typeof str !== 'string') return str;
  return str
    .replace(/\*\*/g, '')
    .replace(/__/g, '')
    .replace(/^#+\s*/gm, '')
    .replace(/^-\s*/gm, '')
    .replace(/`/g, '')
    .trim();
}

// Validate arrays only contain values from available lists
function filterArray(arr, available) {
  if (!Array.isArray(arr)) return [];
  if (!Array.isArray(available) || !available.length) return [];
  return arr.filter(item => available.includes(item));
}

const result = {
  LectureClassPreparationText: stripMarkdown(aiContent.LectureClassPreparationText || ''),
  LessonVocabulary: stripMarkdown(aiContent.LessonVocabulary || ''),
  ThinkingSkills: stripMarkdown(aiContent.ThinkingSkills || ''),
  LectureClassCloseText: stripMarkdown(aiContent.LectureClassCloseText || ''),
  TeacherNote: stripMarkdown(aiContent.TeacherNote || ''),
  goals: filterArray(aiContent.goals, inputData.availableGoals),
  strategies: filterArray(aiContent.strategies, inputData.availableStrategies),
  tools: filterArray(aiContent.tools, inputData.availableTools),
  activities: filterArray(aiContent.activities, inputData.availableActivities),
  homework: stripMarkdown(aiContent.homework || ''),
  preparationActivity: stripMarkdown(aiContent.preparationActivity || ''),
  closureActivity: stripMarkdown(aiContent.closureActivity || ''),
  examGoal: stripMarkdown(aiContent.examGoal || ''),
  // Backwards compatibility with old extension code:
  prep: stripMarkdown(aiContent.LectureClassPreparationText || ''),
  closure: stripMarkdown(aiContent.LectureClassCloseText || ''),
  vocabulary: stripMarkdown(aiContent.LessonVocabulary || '')
};

return [{ json: result }];
